#!/usr/bin/env node
/**
 * Imports a real source folder into Code Studio project data.
 *
 * Usage:
 *   node scripts/import-studio-project.mjs <sourceDir> <outFile.ts>
 *
 * Example:
 *   node scripts/import-studio-project.mjs \
 *     "G:/SOURCE/microservice-algorithms-parttern-leetcode" \
 *     "app/source-code/projects/microservice-learning/files.generated.ts"
 *
 * The generated file exports `PROJECT_ROOT: FsNode[]` — plug it into a
 * StudioProject in the project's index.ts. Content strings are emitted with
 * JSON.stringify, so no manual template-literal escaping is ever needed.
 */
import fs from 'node:fs';
import path from 'node:path';

const EXCLUDED_DIRS = new Set([
  'node_modules',
  '.git',
  'target',
  'build',
  'dist',
  'out',
  'coverage',
  '.idea',
  '.vscode',
  '.next',
  '.mvn',
  '__pycache__',
]);
const MAX_FILE_BYTES = 300_000;

// Keep in sync with EXT_LANGUAGE in app/source-code/types.ts
const EXT_LANGUAGE = {
  java: 'java',
  xml: 'xml',
  pom: 'xml',
  yml: 'yaml',
  yaml: 'yaml',
  sql: 'sql',
  json: 'json',
  properties: 'properties',
  md: 'markdown',
  sh: 'shell',
  bash: 'shell',
  conf: 'shell',
  txt: 'plaintext',
  js: 'javascript',
  jsx: 'javascript',
  mjs: 'javascript',
  cjs: 'javascript',
  ts: 'javascript',
  tsx: 'javascript',
  css: 'css',
  html: 'html',
  htm: 'html',
  env: 'properties',
  gitignore: 'properties',
  dockerignore: 'properties',
  gitattributes: 'properties',
};

function languageFor(name) {
  if (/^dockerfile$/i.test(name)) return 'dockerfile';
  const ext = name.includes('.') ? name.split('.').pop().toLowerCase() : '';
  return EXT_LANGUAGE[ext] ?? null;
}

function isProbablyText(buffer) {
  const sample = Math.min(buffer.length, 4096);
  for (let i = 0; i < sample; i++) {
    if (buffer[i] === 0) return false;
  }
  return true;
}

const skipped = [];
let fileCount = 0;
let totalBytes = 0;

function walk(dir) {
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  const folders = [];
  const files = [];

  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      if (EXCLUDED_DIRS.has(entry.name)) continue;
      const children = walk(full);
      if (children.length > 0) folders.push({ type: 'folder', name: entry.name, children });
      continue;
    }
    if (!entry.isFile()) continue;

    const stat = fs.statSync(full);
    if (stat.size > MAX_FILE_BYTES) {
      skipped.push(`${full} (${stat.size} bytes > ${MAX_FILE_BYTES})`);
      continue;
    }
    const buffer = fs.readFileSync(full);
    if (!isProbablyText(buffer)) {
      skipped.push(`${full} (binary)`);
      continue;
    }
    const language = languageFor(entry.name) ?? 'plaintext';
    const content = buffer
      .toString('utf8')
      .replace(/\r\n/g, '\n')
      .replace(/^\uFEFF/, '');
    files.push({ type: 'file', name: entry.name, language, content });
    fileCount++;
    totalBytes += stat.size;
  }

  const byName = (a, b) => a.name.toLowerCase().localeCompare(b.name.toLowerCase());
  folders.sort(byName);
  files.sort(byName);
  return [...folders, ...files]; // folders first, like the VS Code explorer
}

const [sourceDir, outFile] = process.argv.slice(2);
if (!sourceDir || !outFile) {
  console.error('Usage: node scripts/import-studio-project.mjs <sourceDir> <outFile.ts>');
  process.exit(1);
}
if (!fs.existsSync(sourceDir)) {
  console.error(`Source directory not found: ${sourceDir}`);
  process.exit(1);
}

const tree = walk(path.resolve(sourceDir));

const header = `// AUTO-GENERATED by scripts/import-studio-project.mjs — do not edit by hand.
// Source: ${sourceDir.replace(/\\/g, '/')}
// Files: ${fileCount} (${Math.round(totalBytes / 1024)} KB) — regenerate with:
//   node scripts/import-studio-project.mjs "${sourceDir.replace(/\\/g, '/')}" "${outFile.replace(/\\/g, '/')}"
import { FsNode } from '../../types';

export const PROJECT_ROOT: FsNode[] = `;

fs.mkdirSync(path.dirname(path.resolve(outFile)), { recursive: true });
fs.writeFileSync(path.resolve(outFile), header + JSON.stringify(tree, null, 2) + ';\n', 'utf8');

console.log(`Wrote ${outFile}: ${fileCount} files, ${Math.round(totalBytes / 1024)} KB`);
if (skipped.length > 0) {
  console.log(`Skipped ${skipped.length}:`);
  for (const s of skipped) console.log(`  - ${s}`);
}
